VALUES
  ('cpa-moex-00401', 'cpa', 'cpa-moex-111-17b9ba7b', 'sub-cpa-04', NULL, 'single_choice', '以下關於分批成本制（jobcostingsystem）的敘述，何者正確？', '["廣告公司所執行的每一個廣告企畫，可視為一個批次，適合採用分批成本制", "僅適用於製造業，不適用於服務業及零售業等其他產業", "適合用在成本標的為大量相同或是相似的產品時", "公司僅能在分批成本制及分步成本制中擇一採用"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:04+00:00", "source_pdf_sha1": "eccb4a808f75", "answer_pdf_sha1": "4b4b68825e00", "source_family": "moex-gov-tw", "moex": {"exam_code": "111140", "c": "803", "s": "0205", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "成本會計與管理會計", "year": "111", "exam_name": "111年專門職業及技術人員高等考試會計師、不動產估價師、專利師、民間之公證人考試", "original_question_number": 13, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-00402', 'cpa', 'cpa-moex-111-17b9ba7b', 'sub-cpa-04', NULL, 'single_choice', '關於操作成本制（operationcosting），下列敘述何者正確？', '["操作成本制是一種結合作業基礎成本制及標準成本制的混合成本制", "若公司所生產之每批產品相似度高，可適用操作成本制；但前提是每一批次的產品，都需 要有相同的作業流程", "在操作成本制下，產品原料及客製化部分採分批成本制；而加工成本部分，則採分步成本 制處理", "操作成本制是作業基礎成本制的變形，將作業基礎成本制與傳統成本制進行結合"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:04+00:00", "source_pdf_sha1": "eccb4a808f75", "answer_pdf_sha1": "4b4b68825e00", "source_family": "moex-gov-tw", "moex": {"exam_code": "111140", "c": "803", "s": "0205", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "成本會計與管理會計", "year": "111", "exam_name": "111年專門職業及技術人員高等考試會計師、不動產估價師、專利師、民間之公證人考試", "original_question_number": 14, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-00403', 'cpa', 'cpa-moex-111-17b9ba7b', 'sub-cpa-04', NULL, 'single_choice', '甲公司產銷電動車零件，部分成本項目如下： 維修設備保險費用 $64,000 原料投入成本 512,000 客戶交際費用 30,000 廠房水電費用 90,000 銷售人員佣金費用 44,000 生產設備租金費用 144,000 下列成本分析結果何者正確？', '["沉沒成本合計$238,000", "間接成本合計$298,000", "直接成本合計$512,000", "製造成本合計$810,000"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:04+00:00", "source_pdf_sha1": "eccb4a808f75", "answer_pdf_sha1": "4b4b68825e00", "source_family": "moex-gov-tw", "moex": {"exam_code": "111140", "c": "803", "s": "0205", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "成本會計與管理會計", "year": "111", "exam_name": "111年專門職業及技術人員高等考試會計師、不動產估價師、專利師、民間之公證人考試", "original_question_number": 15, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-00404', 'cpa', 'cpa-moex-111-17b9ba7b', 'sub-cpa-04', NULL, 'single_choice', '甲公司X1年期初原料存貨$40,800，期末原料存貨$34,850，期初製成品存貨$81,600，期末製 成品存貨$69,700，銷貨收入$265,625，毛利率20%。X1年製成品成本為何？', '["$130,900", "$142,800", "$200,600", "$224,400"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:04+00:00", "source_pdf_sha1": "eccb4a808f75", "answer_pdf_sha1": "4b4b68825e00", "source_family": "moex-gov-tw", "moex": {"exam_code": "111140", "c": "803", "s": "0205", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "成本會計與管理會計", "year": "111", "exam_name": "111年專門職業及技術人員高等考試會計師、不動產估價師、專利師、民間之公證人考試", "original_question_number": 16, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-00405', 'cpa', 'cpa-moex-111-17b9ba7b', 'sub-cpa-04', NULL, 'single_choice', '臺北會計師事務所共有24位全職員工，員工平均年薪估計為$900,000。個別客戶平均一年使 用450個人工小時，所有人工成本均為直接成本，並按人工小時數分配至各工作批次；此外， 此會計師事務所的所有間接成本，按總人工小時數進行分攤，20X1 年間接成本預計為 $8,100,000且預計有80個客戶，若20X1年4月為甲公司所提供之審計服務共計使用510個 人工小時，且無其他直接成本，該事務所執行甲公司審計工作之成本是多少？', '["$371,250", "$384,750", "$407,250", "$420,750"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:04+00:00", "source_pdf_sha1": "eccb4a808f75", "answer_pdf_sha1": "4b4b68825e00", "source_family": "moex-gov-tw", "moex": {"exam_code": "111140", "c": "803", "s": "0205", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "成本會計與管理會計", "year": "111", "exam_name": "111年專門職業及技術人員高等考試會計師、不動產估價師、專利師、民間之公證人考試", "original_question_number": 17, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-00406', 'cpa', 'cpa-moex-111-17b9ba7b', 'sub-cpa-04', NULL, 'single_choice', '關於及時系統（Just-in-time(JIT)system）之敘述，下列何者錯誤？', '["有助於減少公司的存貨持有成本", "採用及時系統一定會造成公司的製造費用大幅增加", "採用及時採購（Just-in-time(JIT)purchasing）的公司，需謹慎選擇供應商，並與供應商發展 及維持長期關係", "及時系統可能有助於降低驗收相關費用"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:04+00:00", "source_pdf_sha1": "eccb4a808f75", "answer_pdf_sha1": "4b4b68825e00", "source_family": "moex-gov-tw", "moex": {"exam_code": "111140", "c": "803", "s": "0205", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "成本會計與管理會計", "year": "111", "exam_name": "111年專門職業及技術人員高等考試會計師、不動產估價師、專利師、民間之公證人考試", "original_question_number": 18, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-00407', 'cpa', 'cpa-moex-111-17b9ba7b', 'sub-cpa-04', NULL, 'single_choice', '甲公司20X1年1月份預計損益表資料如下： 銷貨收入（60,000單位） $60,000 銷貨成本（固定生產成本$10,000） 40,000 銷貨毛利 20,000 營業費用（皆變動費用） 10,000 淨利 $10,000 該公司實行改善式預算制度（Kaizenbudgeting），預算目標是變動生產成本每月持續改進降低 1%，營業費用每月持續改進降低2%，若生產量與銷貨量皆不變，則20X1年3月份的淨利 為何？', '["$10,993", "$9,993", "$11,192", "$10,500"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:04+00:00", "source_pdf_sha1": "eccb4a808f75", "answer_pdf_sha1": "4b4b68825e00", "source_family": "moex-gov-tw", "moex": {"exam_code": "111140", "c": "803", "s": "0205", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "成本會計與管理會計", "year": "111", "exam_name": "111年專門職業及技術人員高等考試會計師、不動產估價師、專利師、民間之公證人考試", "original_question_number": 19, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-00408', 'cpa', 'cpa-moex-111-17b9ba7b', 'sub-cpa-04', NULL, 'single_choice', '用來評估投資方案的內部報酬率，其隱含的假設為投資方案所產生的現金流量，可以下列何 者表示之報酬率再投資？', '["會計報酬率", "內部報酬率", "必要報酬率", "營收報酬率"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:04+00:00", "source_pdf_sha1": "eccb4a808f75", "answer_pdf_sha1": "4b4b68825e00", "source_family": "moex-gov-tw", "moex": {"exam_code": "111140", "c": "803", "s": "0205", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "成本會計與管理會計", "year": "111", "exam_name": "111年專門職業及技術人員高等考試會計師、不動產估價師、專利師、民間之公證人考試", "original_question_number": 20, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-00409', 'cpa', 'cpa-moex-111-17b9ba7b', 'sub-cpa-04', NULL, 'single_choice', '甲公司製造運動用品，採用先進先出分步成本制，原料在製程一開始投入，加工成本在製程 中均勻投入。8月份資訊如下： 單位數 原料成本 加工成本 期初在製品存貨（期初完工程度35%） 12,000 $14,250 $16,500 本期開始生產 52,000 $123,000 $167,500 期末在製品存貨（期末完工程度40%） 7,250 8月份完工轉出成本，最接近下列何者？', '["$285,978", "$295,350", "$382,510", "$615,625"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:04+00:00", "source_pdf_sha1": "eccb4a808f75", "answer_pdf_sha1": "4b4b68825e00", "source_family": "moex-gov-tw", "moex": {"exam_code": "111140", "c": "803", "s": "0205", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "成本會計與管理會計", "year": "111", "exam_name": "111年專門職業及技術人員高等考試會計師、不動產估價師、專利師、民間之公證人考試", "original_question_number": 21, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-00410', 'cpa', 'cpa-moex-111-17b9ba7b', 'sub-cpa-04', NULL, 'single_choice', '星月公司產銷單一產品，訂價方法採取以投資報酬率為基礎之成本加成訂價法。依照此方法 所訂出之單位售價為$250，並預估在此價格下每年可銷售 3,000 單位。公司之投資額為 $600,000，投資報酬率為12%。試問依成本總額加成百分比為多少？', '["7.14%", "8.76%", "9.60%", "10.62%"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:04+00:00", "source_pdf_sha1": "eccb4a808f75", "answer_pdf_sha1": "4b4b68825e00", "source_family": "moex-gov-tw", "moex": {"exam_code": "111140", "c": "803", "s": "0205", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "成本會計與管理會計", "year": "111", "exam_name": "111年專門職業及技術人員高等考試會計師、不動產估價師、專利師、民間之公證人考試", "original_question_number": 22, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL)
